+    if !dry_run {
+        let report_path =
+            doctor_archive_report_path(&storage_root, "archive-normalize", &timestamp);
+        write_doctor_json_report(
+            &report_path,
+            &serde_json::json!({
+                "audit": &report,
+                "result": &result,
+            }),
+        )?;
+        result.report_path = Some(report_path.display().to_string());
+    }
+
+    if json {
